def default_config_path_for_init(cli_path):
    """For config-init: pick the path where we'd create the default config."""
    if cli_path is not None:
        return cli_path
    xdg = os.environ.get('XDG_CONFIG_HOME')
    home = os.environ.get('HOME')
    if not xdg and home:
