    args['from_alias'] = pos[0]
    args['to_alias'] = pos[1]
    opts['sub_args'] = args


def main():
    argv = sys.argv[1:]
    opts = parse_args(argv)
    sub = opts['sub']
    if sub == 'add':
        cmd_add(opts)
    elif sub == 'remove':
