def parse_copy(argv, opts):
    if len(argv) < 2:
        which = '<from-alias>' if len(argv) == 0 else '<to-alias>'
        err(f"error: The following required arguments were not provided:\n    {which}\n\nUSAGE:\n    executable copy <from-alias> <to-alias>\n\nFor more information try --help\n")
    if len(argv) > 2:
        err(f"error: Found argument '{argv[2]}' which wasn't expected, or isn't valid in this context\n\nUSAGE:\n    executable copy <from-alias> <to-alias>\n\nFor more information try --help\n")
