    del cfg.scripts[alias]
    cfg.write()
    out(f"Removed {alias}\n")


def cmd_show(opts):
    args = opts['sub_args']
    alias = args['alias']
    cfg = load_config(opts)
    if not cfg.scripts:
        err("error: No scripts exist. Would you like to add a new script?\n")
    if alias not in cfg.scripts:
