    opts['sub_args'] = args


def parse_copy(argv, opts):
    if len(argv) < 2:
        which = '<from-alias>' if len(argv) == 0 else '<to-alias>'
        err(f"error: The following required arguments were not provided:\n    {which}\n\nUSAGE:\n    executable copy <from-alias> <to-alias>\n\nFor more information try --help\n")
    if len(argv) > 2:
        err(f"error: Found argument '{argv[2]}' which wasn't expected, or isn't valid in this context\n\nUSAGE:\n    executable copy <from-alias> <to-alias>\n\nFor more information try --help\n")
    opts['sub_args'] = {'from_alias': argv[0], 'to_alias': argv[1]}


def parse_move(argv, opts):
    args = {'force': False, 'from_alias': None, 'to_alias': None}
    pos = []
    i = 0
    while i < len(argv):
        a = argv[i]
        if a == '-f' or a == '--force':
            args['force'] = True; i += 1; continue
        pos.append(a)
        i += 1
    if len(pos) < 2:
        which = '<from-alias>' if len(pos) == 0 else '<to-alias>'
        err(f"error: The following required arguments were not provided:\n    {which}\n\nUSAGE:\n    executable move [FLAGS] <from-alias> <to-alias>\n\nFor more information try --help\n")
    if len(pos) > 2:
        err(f"error: Found argument '{pos[2]}' which wasn't expected, or isn't valid in this context\n\nUSAGE:\n    executable move [FLAGS] <from-alias> <to-alias>\n\nFor more information try --help\n")
    args['from_alias'] = pos[0]
    args['to_alias'] = pos[1]
    opts['sub_args'] = args


def main():
    argv = sys.argv[1:]
    opts = parse_args(argv)
    sub = opts['sub']
    if sub == 'add':
        cmd_add(opts)
    elif sub == 'remove':
        cmd_remove(opts)
    elif sub == 'show':
        cmd_show(opts)
    elif sub == 'edit':
        cmd_edit(opts)
    elif sub == 'run':
        cmd_run(opts)
    elif sub == 'list':
        cmd_list(opts)
    elif sub == 'copy':
        cmd_copy(opts)
    elif sub == 'move':
        cmd_move(opts)
    elif sub == 'config-init':
        cmd_config_init(opts)
    else:
        err(f"error: subcommand {sub} not implemented\n")


if __name__ == '__main__':
    try:
        main()
    except BrokenPipeError:
        sys.exit(0)
    except KeyboardInterrupt:
