import shutil

VERSION = "0.1.6"
HELLO_PIER_CONFIG = "[scripts.hello-pier]\ncommand = 'echo Hello, Pier!'\ndescription = 'This is an example command.'\n\n[default]\n"

# Subcommands and aliases. (None means no alias)
